import{o as n,c as s,d as a}from"./app.a15502cc.js";const t='{"title":"函数","description":"","frontmatter":{},"headers":[{"level":2,"title":"函数声明","slug":"函数声明"},{"level":2,"title":"注意事项","slug":"注意事项"},{"level":2,"title":"匿名函数","slug":"匿名函数"},{"level":2,"title":"defer","slug":"defer"},{"level":2,"title":"系统函数","slug":"系统函数"},{"level":3,"title":"init","slug":"init"},{"level":2,"title":"内置函数","slug":"内置函数"},{"level":3,"title":"new","slug":"new"},{"level":3,"title":"make","slug":"make"}],"relativePath":"docs/golang/base/functions.md","lastUpdated":1640748203000}',p={},o=a('<h1 id="函数"><a class="header-anchor" href="#函数" aria-hidden="true">#</a> 函数</h1><h2 id="函数声明"><a class="header-anchor" href="#函数声明" aria-hidden="true">#</a> 函数声明</h2><p>函数声明包括函数名、形式参数列表、返回值列表（可省略）以及函数体</p><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">name</span><span class="token punctuation">(</span>parameter<span class="token operator">-</span>list<span class="token punctuation">)</span> <span class="token punctuation">(</span>result<span class="token operator">-</span>list<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token comment">// body</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h2 id="注意事项"><a class="header-anchor" href="#注意事项" aria-hidden="true">#</a> 注意事项</h2><ol><li><p>函数的形参列表可以是多个，返回值也可以是多个</p></li><li><p>形参列表和返回值列表的数据类型可以是值类型和引用类型</p></li><li><p>函数的命名规范遵循标识符命名规范，首字母不能是数字，首字母大写的函数可以被本包文件和其它包文件使用，类似public，首字母小写的函数只能被本包文件使用，类似private</p></li><li><p>函数中的变量是局部的，函数外不能使用</p></li><li><p>基本数据类型和数组、结构体默认都是值传递，即进行值拷贝。在函数内部修改不会影响原来的值，如果希望函数内部能修改函数外部的变量，可以传入变量的地址&amp;，函数内部以指针的方式操作变量</p></li><li><p>Go函数不支持重载</p></li><li><p>在Go中<strong>函数也是一种数据类型</strong>，可以赋值给一个变量，则该变量就是一个函数类型的变量了，通过该变量可以对函数进行调用</p></li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">getsum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> n1 <span class="token operator">+</span> n2\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  a <span class="token operator">:=</span> getsum\n  res <span class="token operator">=</span> <span class="token function">a</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span><span class="token number">20</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;res的数据类型是%T getsum的数据类型是%T&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">,</span> getsum<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><div class="language-go"><pre><code>res的数据类型是<span class="token keyword">func</span><span class="token punctuation">(</span><span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> getsum的数据类型是<span class="token keyword">func</span><span class="token punctuation">(</span><span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span>\n</code></pre></div><ol start="8"><li>函数是一种数据类型，因此在Go中，函数可以作为形参，并且调用</li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">getSum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> n1 <span class="token operator">+</span> n2\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">myFun</span><span class="token punctuation">(</span>funvar <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span><span class="token punctuation">,</span> num1 <span class="token builtin">int</span><span class="token punctuation">,</span> num2 <span class="token builtin">int</span> <span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token function">funvar</span><span class="token punctuation">(</span>num1<span class="token punctuation">,</span> num2<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  res <span class="token operator">:=</span> <span class="token function">myFun</span><span class="token punctuation">(</span>getSum<span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">30</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><ol start="9"><li>为了简化数据类型定义，Go支持自定义数据类型</li></ol><p>基本语法：type 自定义数据类型名 数据类型 // 理解：相当于一个别名 案例1：type myInt int // myInt等价int 案例2：type mySum func(int, int) int // mySum等价于一个函数类型func(int, int) int</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">getSum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> n1 <span class="token operator">+</span> n2\n<span class="token punctuation">}</span>\n\n<span class="token keyword">type</span> myFunType <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span>\n\n<span class="token keyword">func</span> <span class="token function">myFun</span><span class="token punctuation">(</span>funvar myFunType<span class="token punctuation">,</span> num1 <span class="token builtin">int</span><span class="token punctuation">,</span> num2 <span class="token builtin">int</span> <span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token function">funvar</span><span class="token punctuation">(</span>num1<span class="token punctuation">,</span> num2<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  <span class="token comment">// 给int取了别名，在go中myInt虽然是int类型，但是go认为myInt和int是两个不同的类型</span>\n  <span class="token keyword">type</span> myInt <span class="token operator">=</span> <span class="token builtin">int</span>\n  <span class="token keyword">var</span> num1 myInt\n  <span class="token keyword">var</span> num2 <span class="token builtin">int</span>\n  num1 <span class="token operator">=</span> <span class="token number">40</span>\n  num2 <span class="token operator">=</span> <span class="token function">int</span><span class="token punctuation">(</span>num1<span class="token punctuation">)</span> <span class="token comment">// 这里需要显示转换</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;num1 =&quot;</span><span class="token punctuation">,</span> num1<span class="token punctuation">,</span> <span class="token string">&quot;num2 =&quot;</span><span class="token punctuation">,</span> num2<span class="token punctuation">)</span>\n\n  res <span class="token operator">:=</span> <span class="token function">myFun</span><span class="token punctuation">(</span>getSum<span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">30</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><ol start="10"><li>支持对函数返回值命名</li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">cal</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>sum <span class="token builtin">int</span><span class="token punctuation">,</span> sub <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  sum <span class="token operator">=</span> n1 <span class="token operator">+</span> n2\n  sub <span class="token operator">=</span> n1 <span class="token operator">-</span> n2\n  <span class="token keyword">return</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  <span class="token keyword">var</span> n1 <span class="token builtin">int</span> <span class="token operator">=</span> <span class="token number">1</span>\n  <span class="token keyword">var</span> n2 <span class="token builtin">int</span> <span class="token operator">=</span> <span class="token number">2</span>\n  sum<span class="token punctuation">,</span> sub <span class="token operator">:=</span> <span class="token function">cal</span><span class="token punctuation">(</span>n1<span class="token punctuation">,</span> n2<span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;sum=&quot;</span><span class="token punctuation">,</span> sum<span class="token punctuation">,</span> <span class="token string">&quot;sub=&quot;</span><span class="token punctuation">,</span> sub<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><ol start="11"><li><p>使用 _ 标识符，忽略返回值</p></li><li><p>Go支持可变参数</p></li></ol><div class="language-go"><pre><code><span class="token comment">// 支持0到多个参数</span>\n<span class="token keyword">func</span> <span class="token function">sum</span><span class="token punctuation">(</span>args<span class="token operator">...</span><span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n<span class="token punctuation">}</span>\n<span class="token comment">// 支持1到多个参数</span>\n<span class="token keyword">func</span> <span class="token function">sum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> args<span class="token operator">...</span><span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n<span class="token punctuation">}</span>\n</code></pre></div><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">sum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> args<span class="token operator">...</span><span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  res <span class="token operator">:=</span> n1\n  <span class="token keyword">for</span> i<span class="token operator">:=</span><span class="token number">0</span><span class="token punctuation">;</span> i<span class="token operator">&lt;=</span><span class="token function">len</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">;</span> i<span class="token operator">++</span> <span class="token punctuation">{</span>\n      res <span class="token operator">+=</span> args<span class="token punctuation">[</span>i<span class="token punctuation">]</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">return</span> res\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  res <span class="token operator">:=</span> <span class="token function">sum</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">,</span><span class="token number">4</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h2 id="匿名函数"><a class="header-anchor" href="#匿名函数" aria-hidden="true">#</a> 匿名函数</h2><p>在定义时直接调用，将匿名函数赋值给一个变量，再通过该函数调用匿名函数</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  res1 <span class="token operator">:=</span> <span class="token keyword">func</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n      <span class="token keyword">return</span> n1 <span class="token operator">+</span> n2\n  <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res1 =&quot;</span><span class="token punctuation">,</span> res1<span class="token punctuation">)</span>\n\n  a <span class="token operator">:=</span> <span class="token keyword">func</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n      <span class="token keyword">return</span> n1 <span class="token operator">-</span> n2\n  <span class="token punctuation">}</span>\n  res2 <span class="token operator">:=</span> <span class="token function">a</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span><span class="token number">20</span><span class="token punctuation">)</span>\n  res3 <span class="token operator">:=</span> <span class="token function">a</span><span class="token punctuation">(</span><span class="token number">20</span><span class="token punctuation">,</span><span class="token number">10</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res2 =&quot;</span><span class="token punctuation">,</span> res2<span class="token punctuation">,</span> <span class="token string">&quot;res3 =&quot;</span><span class="token punctuation">,</span> res3<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>全局匿名函数在程序的各个地方都可以调用</p><h2 id="defer"><a class="header-anchor" href="#defer" aria-hidden="true">#</a> defer</h2><ol><li><p>go执行到一个defer时，不会立即执行defer后的语句，而是将defer后的语句压入到一个栈中，然后继续执行函数下面的语句。<strong>defer将语句放入栈时，也会将相关的值拷贝入栈</strong></p></li><li><p>函数执行完毕后，再从defer栈中依次取出语句执行（遵循栈先入后出的规则 FILO）</p></li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">sum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;n1 =&quot;</span><span class="token punctuation">,</span> n1<span class="token punctuation">)</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;n2 =&quot;</span><span class="token punctuation">,</span> n2<span class="token punctuation">)</span>\n  n1<span class="token operator">++</span>\n  n2<span class="token operator">++</span>\n  res <span class="token operator">:=</span> n1 <span class="token operator">+</span> n2\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n  <span class="token keyword">return</span> res\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  res <span class="token operator">:=</span> <span class="token function">sum</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span><span class="token number">20</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;main res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><ol start="3"><li>defer、return、返回值三者的执行逻辑应该是：return最先执行，return负责将结果写入返回值中；接着defer开始执行一些收尾工作；最后函数携带当前返回值退出。如果函数的返回值是无名的（不带命名返回值），则go语言会在执行return的时候会执行一个类似创建一个临时变量作为保存return值的动作，而有名返回值的函数，由于返回值在函数定义的时候已经将该变量进行定义，在执行return的时候会先执行返回值保存操作，而后续的defer函数会改变这个返回值(虽然defer是在return之后执行的，但是由于使用的函数定义的变量，所以执行defer操作后对该变量的修改会影响到return的值。</li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n    <span class="token string">&quot;fmt&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n    a <span class="token operator">:=</span> <span class="token number">1</span>\n    <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        a <span class="token operator">=</span> <span class="token number">4</span>\n    <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token keyword">return</span> a\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    a <span class="token operator">:=</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;a&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\na <span class="token number">1</span>\n</code></pre></div><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n    <span class="token string">&quot;fmt&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>a <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    a <span class="token operator">=</span> <span class="token number">1</span>\n    <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        a <span class="token operator">=</span> <span class="token number">4</span>\n    <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token keyword">return</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    a <span class="token operator">:=</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;a&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\na <span class="token number">4</span>\n</code></pre></div><ol start="4"><li>defer最主要的价值是在当函数执行完毕后，可以及时释放函数创建的资源</li></ol><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  connect <span class="token operator">=</span> <span class="token function">openDatabase</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">defer</span> connect<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token comment">// 其它代码</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h2 id="系统函数"><a class="header-anchor" href="#系统函数" aria-hidden="true">#</a> 系统函数</h2><h3 id="init"><a class="header-anchor" href="#init" aria-hidden="true">#</a> init</h3><p><strong>每一个源文件都可以包含一个init函数</strong>，该函数会在main函数执行前，被调用运行</p><p>如果一个文件同时包含全局定义变量，init函数，main函数，则执行的流程是 全局变量定义 -&gt; init -&gt; main</p><h2 id="内置函数"><a class="header-anchor" href="#内置函数" aria-hidden="true">#</a> 内置函数</h2><h3 id="new"><a class="header-anchor" href="#new" aria-hidden="true">#</a> new</h3><p>用来分配内存，主要用来分配值类型，比如int、float32、struct...返回的是指针</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  num <span class="token operator">:=</span> <span class="token function">new</span><span class="token punctuation">(</span><span class="token builtin">int</span><span class="token punctuation">)</span>\n  <span class="token operator">*</span>num <span class="token operator">=</span> <span class="token number">100</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;num的类型=%T num的值=%v num的地址=%v num指向的值=%v&quot;</span><span class="token punctuation">,</span> num<span class="token punctuation">,</span> num<span class="token punctuation">,</span> <span class="token operator">&amp;</span>num<span class="token punctuation">,</span> <span class="token operator">*</span>num<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="make"><a class="header-anchor" href="#make" aria-hidden="true">#</a> make</h3><p>用来分配内存，主要用来分配引用类型</p>',40);p.render=function(a,t,p,e,c,u){return n(),s("div",null,[o])};export default p;export{t as __pageData};
